    '300 Workout Challenge',
    '300 Workout Challenge - 4w 3x/wk',
    'High',
    false,
    'Complete 300 reps as fast as possible - Spartan-inspired',
    'Hell Mode'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = '300 Workout Challenge'
  AND pv.duration_weeks = 4
  AND pv.sessions_per_week = 3
ON CONFLICT DO NOTHING;

